+    while (true) {
+      if (existsSync(join(current, ".git"))) {
+        return basename(current);
+      }
+
+      const parent = dirname(current);
+      if (parent === current) {
+        break;
+      }
+
+      current = parent;
+    }
+
+    return basename(resolve(startDir));
+  }
